// Normalize 永慶 URL and extract case ID.
// Accepts both YC-prefixed and digit-only forms; produces a canonical URL
// that we use as the dedup key against Notion's 來源連結 column.
const raw = String($json.url || '').trim();
if (!raw) {
  throw new Error('缺少永慶網址');
}

// Strip query string / hash, force https, lowercase host.
let u;
try {
  u = new URL(raw);
} catch (e) {
  throw new Error('網址格式錯誤：' + raw);
}
u.hash = '';
u.search = '';
u.protocol = 'https:';
u.hostname = u.hostname.toLowerCase();

// Match /house/<caseId> — caseId is digits, optionally prefixed with YC.
const m = u.pathname.match(/\/house\/(YC)?(\d+)/i);
if (!m) {
  throw new Error('無法從網址解析案件編號：' + raw);
}
const caseId = 'YC' + m[2];                       // canonical YC-prefixed form
const pathCaseSegment = (m[1] ? 'YC' : '') + m[2]; // preserve original prefix in URL
u.pathname = `/house/${pathCaseSegment}`;
if (u.pathname.endsWith('/')) u.pathname = u.pathname.slice(0, -1);

return [{
  json: {
    sourceUrl: u.toString(),
    caseId,
    lineUserId: $json.lineUserId || '',
    replyToken: $json.replyToken || ''
  }
}];

// Parse 永慶物件頁 HTML.
//
// 永慶 SSR pages embed structured data inside a <script id="__NEXT_DATA__">
// JSON blob. Selectors below are intentionally tolerant: we try the JSON
// blob first, then fall back to lightweight regex/cheerio-style scraping on
// visible markup. If 永慶 changes their template, only this node should need
// updating.
const html = String($json.data || $json.body || '');
const input = $('Normalize URL').first().json;

function text(re) {
  const m = html.match(re);
  return m ? m[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim() : '';
}
function num(s) {
  if (!s) return null;
  const m = String(s).match(/-?\d+(?:\.\d+)?/);
  return m ? Number(m[0]) : null;
}

// 1. Try __NEXT_DATA__ JSON.
let data = null;
const nd = html.match(/<script[^>]*id="__NEXT_DATA__"[^>]*>([\s\S]*?)<\/script>/);
if (nd) {
  try {
    const parsed = JSON.parse(nd[1]);
    data = parsed?.props?.pageProps?.detail
        || parsed?.props?.pageProps?.house
        || parsed?.props?.pageProps?.data
        || null;
  } catch (e) { /* fall through to regex */ }
}

let name        = data?.caseName        || data?.communityName  || text(/<h1[^>]*>([\s\S]*?)<\/h1>/);
let community   = data?.communityName   || '';
let address     = data?.address         || data?.fullAddress    || text(/地[\s　]*址[^<]*<[^>]*>([^<]+)/);
let totalPrice  = data?.totalPriceDisplay || data?.totalPrice    || text(/總[\s　]*價[^<]*<[^>]*>([^<]+)/);
let unitPrice   = data?.unitPriceDisplay  || data?.unitPrice     || text(/單[\s　]*價[^<]*<[^>]*>([^<]+)/);
let layout      = data?.layout            || text(/格[\s　]*局[^<]*<[^>]*>([^<]+)/);
let floor       = data?.floor             || text(/樓[\s　]*層[^<]*<[^>]*>([^<]+)/);
let age         = num(data?.houseAge)     ?? num(text(/屋[\s　]*齡[^<]*<[^>]*>([^<]+)/));
let mainArea    = num(data?.mainBuildingArea) ?? num(text(/主建物[^<]*<[^>]*>([^<]+)/));
let publicArea  = num(data?.publicArea)       ?? num(text(/公[\s　]*設[^<]*<[^>]*>([^<]+)/));
let buildArea   = num(data?.buildingArea)     ?? num(text(/建[\s　]*坪[^<]*<[^>]*>([^<]+)/));
let landArea    = num(data?.landArea)         ?? num(text(/土地[^<]*<[^>]*>([^<]+)/));
let attached    = data?.attachedBuilding      || text(/附屬建物[^<]*<[^>]*>([^<]+)/);
let description = data?.description           || text(/<meta name="description" content="([^"]+)"/);

// Building type heuristic (must map to a select option).
const typeMap = ['公寓', '華廈', '電梯大樓', '透天', '套房', '店面'];
let buildingType = data?.buildingType || '';
if (!buildingType) {
  for (const t of typeMap) {
    if (html.includes(t)) { buildingType = t; break; }
  }
}
if (!typeMap.includes(buildingType)) buildingType = '其他';

// Parking — checkbox + select.
const hasParking = /有車位|平面車位|機械車位|坡道車位/.test(html);
let parkingType = '無';
if (/坡道平面/.test(html)) parkingType = '坡道平面';
else if (/機械/.test(html))   parkingType = '機械';
else if (/法定/.test(html))   parkingType = '法定';

// Photos: collect og:image + first N gallery URLs (Notion file column wants URLs).
const photos = new Set();
const og = html.match(/<meta property="og:image" content="([^"]+)"/);
if (og) photos.add(og[1]);
const imgRe = /https:\/\/[\w./%-]*yungching[\w./%-]*\.(?:jpe?g|png|webp)/gi;
let im;
while ((im = imgRe.exec(html)) && photos.size < 8) photos.add(im[0]);

return [{
  json: {
    sourceUrl: input.sourceUrl,
    caseId: input.caseId,
    lineUserId: input.lineUserId,
    replyToken: input.replyToken,
    parsed: {
      案名: name || input.caseId,
      社區名稱: community,
      地址: address,
      總價: totalPrice,
      單價: unitPrice,
      格局: layout,
      樓層: floor,
      屋齡: age,
      主建物坪數: mainArea,
      公設坪數: publicArea,
      建物坪數: buildArea,
      土地坪數: landArea,
      附屬建物: attached,
      特色說明: description,
      建物類型: buildingType,
      有無車位: hasParking,
      車位類型: parkingType,
      物件照片: Array.from(photos)
    }
  }
}];

// Notion node returns 0..1 page item. Pass through the parsed property
// alongside an `existingPageId` (or null) so downstream branches stay simple.
const parsed = $('Parse Property HTML').first().json;
const hits   = $input.all();
const existing = hits.length > 0 && hits[0].json && hits[0].json.id ? hits[0].json : null;
return [{
  json: {
    ...parsed,
    existingPageId: existing ? existing.id : null,
    existingVersion: existing?.properties?.['文案版本']?.number ?? 0
  }
}];

// Build a short LINE-style reply string. Caller (LINE 指令分流) is
// responsible for actually pushing/replying via the LINE API.
const page = $json;
const attached = $('Attach Lookup Result').first().json;
const action = attached.existingPageId ? '更新' : '新增';
const name   = attached.parsed?.['案名'] || attached.caseId;
const price  = attached.parsed?.['總價'] || '';
const layout = attached.parsed?.['格局'] || '';
const pageUrl = page?.url || page?.public_url || '';
const lines = [
  `✅ 已${action}：${name}`,
  price && `總價：${price}`,
  layout && `格局：${layout}`,
  `案件編號：${attached.caseId}`,
  pageUrl && `Notion：${pageUrl}`
].filter(Boolean);
return [{
  json: {
    action,
    notionPageId: page?.id || null,
    notionPageUrl: pageUrl,
    caseId: attached.caseId,
    sourceUrl: attached.sourceUrl,
    replyText: lines.join('\n'),
    replyToken: attached.replyToken,
    lineUserId: attached.lineUserId
  }
}];
